it("should calculate base premium for sword (100 G)", () => {
  const scenario = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote",
        items: [{ type: "sword" }]
      }
    ]
  };
  const result = processScenario(scenario);
  expect(result.results[0].premium).toBe(105); // 100 base + 5 fee
});

