function getBasePremium(itemType) {
  const basePremiums = {
    sword: 100,
    amulet: 60,
    staff: 80,
    potion: 40,
    component: 25
  };
  return basePremiums[itemType] || 0;
}

export function processScenario(scenario) {
  let basePremium = 0;

  // Handle the format with steps and items
  if (scenario.steps && scenario.steps[0]?.items) {
    const item = scenario.steps[0].items[0];
    basePremium = getBasePremium(item.type);
  }
  // Handle the format with explicit risk and basePremium
  else if (scenario.basePremium !== undefined) {
    basePremium = scenario.basePremium;
  }

  return {
    results: [
      {
        premium: basePremium + 5 // 5 G fee
      }
    ]
  };
}

