const ITEM_BASE_PREMIUMS = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  component: 25
};

const PROCESSING_FEE = 5;

export function processScenario(scenario) {
  let basePremium = 0;

  // Determine base premium based on scenario format
  if (hasStepsFormat(scenario)) {
    // Format with steps and items
    const item = getFirstItem(scenario);
    basePremium = ITEM_BASE_PREMIUMS[item.type] || 0;
  } else if (hasDirectFormat(scenario)) {
    // Format with explicit basePremium
    basePremium = scenario.basePremium;
  }

  return {
    results: [
      {
        premium: basePremium + PROCESSING_FEE
      }
    ]
  };
}

function hasStepsFormat(scenario) {
  return scenario.steps?.[0]?.items?.[0] !== undefined;
}

function hasDirectFormat(scenario) {
  return scenario.basePremium !== undefined;
}

function getFirstItem(scenario) {
  return scenario.steps[0].items[0];
}

