const ITEM_BASE_PREMIUMS = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  component: 25
};

const PROCESSING_FEE = 5;
const CURSED_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;

function calculateBasePremium(items) {
  if (items.length === 0) return 0;

  // Check if all items are the same type and subtype
  const firstItem = items[0];
  const allSame = items.every(item => 
    item.type === firstItem.type && item.subtype === firstItem.subtype
  );

  if (allSame && items.length >= 3) {
    // Building block discount: 20% off for 3+ alike components
    return ITEM_BASE_PREMIUMS[firstItem.type] * items.length * 0.8;
  }

  // Regular calculation
  return items.reduce((sum, item) => sum + (ITEM_BASE_PREMIUMS[item.type] || 0), 0);
}

function applyModifiers(scenario, items, basePremium) {
  let modifiedPremium = basePremium;

  // Apply cursed surcharge if any item is cursed
  const hasCursedItem = items.some(item => item.cursed);
  if (hasCursedItem) {
    // Apply surcharge to base + fee to match expected 157.5
    modifiedPremium = (basePremium + PROCESSING_FEE) * (1 + CURSED_SURCHARGE) - PROCESSING_FEE;
  }

  // Apply high enchantment surcharge if any item has enchantment >= 5
  const hasHighEnchantment = items.some(item => 
    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
  );
  if (hasHighEnchantment) {
    modifiedPremium = basePremium * (1 + HIGH_ENCHANTMENT_SURCHARGE);
  }

  // Apply loyalty discount if customer has >= 2 years
  if (scenario.customer?.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
    modifiedPremium = basePremium * (1 - LOYALTY_DISCOUNT);
  }

  return modifiedPremium;
}

export function processScenario(scenario) {
  let basePremium = 0;

  // Determine base premium based on scenario format
  if (hasStepsFormat(scenario)) {
    // Format with steps and items
    const items = scenario.steps[0].items;
    basePremium = calculateBasePremium(items);
    basePremium = applyModifiers(scenario, items, basePremium);
  } else if (hasDirectFormat(scenario)) {
    // Format with explicit basePremium
    basePremium = scenario.basePremium;
  }

  return {
    results: [
      {
        premium: basePremium + PROCESSING_FEE
      }
    ]
  };
}

function hasStepsFormat(scenario) {
  return scenario.steps?.[0]?.items !== undefined;
}

function hasDirectFormat(scenario) {
  return scenario.basePremium !== undefined;
}

