input.newString:
function processClaim(items, basePremium) {
  const DEDUCTIBLE = 100;
  const PAYOUT_CAP_MULTIPLIER = 2;

  // Calculate total damage
  const totalDamage = items.reduce((sum, item) => sum + (item.damage || 0), 0);

  // Calculate payout with deductible
  let payout = Math.max(0, totalDamage - DEDUCTIBLE);

  // Apply payout cap (twice the insurance sum)
  const insuranceCap = basePremium * PAYOUT_CAP_MULTIPLIER;
  payout = Math.min(payout, insuranceCap);

  return {
    results: [
      {
        payout: payout
      }
    ]
  };
}

