function calculateBasePremium(items) {
  if (items.length === 0) return 0;

  // Check for building block discount (exactly 3 alike components)
  const firstItem = items[0];
  const allSame = items.every(item => 
    item.type === firstItem.type && item.subtype === firstItem.subtype
  );

  if (allSame && items.length === 3) {
    return ITEM_BASE_PREMIUMS[firstItem.type] * items.length * 0.8;
  }

  // Regular calculation
  return items.reduce((sum, item) => sum + (ITEM_BASE_PREMIUMS[item.type] || 0), 0);
}

input.newString:
function calculateBasePremium(items) {
  if (items.length === 0) return 0;

  // Group items by type and subtype to apply building block discount per group
  const itemGroups = {};
  items.forEach(item => {
    const key = `${item.type}-${item.subtype}`;
    if (!itemGroups[key]) {
      itemGroups[key] = [];
    }
    itemGroups[key].push(item);
  });

  let totalPremium = 0;

  // Calculate premium for each group
  for (const group of Object.values(itemGroups)) {
    const basePremium = ITEM_BASE_PREMIUMS[group[0].type] || 0;

    // Apply building block discount if exactly 3 items in group
    if (group.length === 3) {
      totalPremium += basePremium * 3 * 0.8;
    } else {
      totalPremium += basePremium * group.length;
    }
  }

  return totalPremium;
}

