input.oldString:
function applyModifiers(scenario, items, basePremium) {
  let modifiedPremium = basePremium;
  const customer = scenario.customer || {};

  // Calculate base premium per item to apply item-specific modifiers
  const itemGroups = groupItemsByTypeAndSubtype(items);
  let totalPremium = 0;

  for (const group of itemGroups) {
    const itemBasePremium = ITEM_BASE_PREMIUMS[group[0].type] || 0;
    const groupPremium = itemBasePremium * group.length;

    // Apply cursed surcharge to cursed items only
    if (group.some(item => item.cursed)) {
      totalPremium += groupPremium * (1 + MODIFIERS.CURSED_SURCHARGE);
    } else if (group.some(item => item.enchantment >= MODIFIERS.HIGH_ENCHANTMENT_THRESHOLD)) {
      totalPremium += groupPremium * (1 + MODIFIERS.HIGH_ENCHANTMENT_SURCHARGE);
    } else {
      totalPremium += groupPremium;
    }
  }

  // Apply customer-specific modifiers to the total premium
  if (customer.followUpContract) {
    totalPremium = totalPremium * (1 - MODIFIERS.FOLLOW_UP_CONTRACT_DISCOUNT);
  } else if (customer.yearsWithMHPCO >= MODIFIERS.LOYALTY_YEARS_THRESHOLD) {
    totalPremium = totalPremium * (1 - MODIFIERS.LOYALTY_DISCOUNT);
  } else if (customer.yearsWithMHPCO === 0) {
    totalPremium = totalPremium * (1 + MODIFIERS.FIRST_INSURANCE_SURCHARGE);
    // Round to avoid floating point precision issues
    totalPremium = Math.round(totalPremium * 100) / 100;
  }

  return totalPremium;
}

